module counter_with_load_enable (
	input clk,
	input reset,
	input load,
	input enable,
	input [31:0] data,
	output reg [31:0] count);

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset)
			count <= 32'b00000000000000000000000000000000;
		else if (load)
			count <= data;
		else if (enable)
			count <= count + 1;
	end

endmodule
